@ARTICLE{10.1188/18.CJON.E159-E165,
	author = {Knox A},
	title = {Fall Risk Perceptions: A Study of Hospitalized Patients With Hematologic Malignancies.},
	journal = {Clin J Oncol Nurs},
	year = {2018},
	abstract = {BACKGROUND: Inpatient falls cause harm, increased length of stay, and high costs. Patients with hematologic malignancies have a unique set of fall risk factors, and studies indicate that patients lack accurate perception of fall risk. OBJECTIVES: This study describes patient perceptions of fall risk in people with hematologic malignancies and compares patient and nurse perceptions of fall risk. METHODS: This mixed-methods study used descriptive statistical and narrative analyses. A convenience sample of patients was interviewed about perception of fall risk. Descriptive analysis of patient data and analysis around correlation between patient and nurse assessment of fall risk were completed. FINDINGS: Themes emerged about participants' prior experience with falls and perceptions of fall education. Participants who reported feeling weak prior to hospitalization perceived being at high fall risk, consistent with nurse assessment. Several patients reported feeling at low risk. Data showed discrepancies in patients' perceptions of nursing education.},
	doi = {10.1188/18.CJON.E159-E165},
	pmid = {30452005 [Indexed for MEDLINE]}
}

@ARTICLE{10.1200/JGO.2016.007906,
	author = {Yanamandra U and Malhotra P and Sahu KK and Sushma Y and Saini N and Chauhan P and Gill J and Rikhi D and Khadwal A and Prakash G and Lad D and Suri V and Kumari S and Varma N and Varma S},
	title = {Variation in Adherence Measures to Imatinib Therapy.},
	journal = {J Glob Oncol},
	year = {2018},
	abstract = {PURPOSE: The introduction of tyrosine kinase inhibitors has transformed the care of patients with chronic myeloid leukemia, with survival approaching that of healthy individuals. Current-day challenges in chronic myeloid leukemia care include adherence to tyrosine kinase inhibitor therapy. We studied adherence from resource-constrained settings and tried to analyze the factors responsible for nonadherence in these individuals. We also correlated adherence to current molecular status. PATIENTS AND METHODS: This was a single-center, cross-sectional, observational study from north India. It consisted of a questionnaire-based survey in which a one-to-one interview technique was used by trained nursing staff administering the Modified Morisky Adherence Scale (MMAS-9) questionnaire. Adherence was also measured on the basis of physician's assessment. JMP 13.0.0 was used for statistical analysis. RESULTS: A total of 333 patients with a median age of 42 years were included in the study. The median BCR-ABL/ABL ratio (IS) was 0.175 (0.0 to 98.0). The mean MMAS-9 score was 11 ± 2. Adherence was seen in 54.95% on the basis of MMAS-9, whereas physician's assessment reported adherence in 90.39% of patients. Using the χ2 test, no relationship was found between the two assessment techniques. There was a significant relationship between major molecular response status and adherence by physician's assessment and MMAS-9 ( P < .001). Bivariate analysis by logistic fit showed a good relation between the MMAS-9 score and the BCR-ABL/ABL ratio (IS), χ2 (1,220) = 135.45 ( P < .001). On multivariate analysis, enrolment in the Novartis Oncology Access program (a patient assistance program) was significantly associated with adherence ( P = .012). CONCLUSION: This study highlights the lack of adherence in real-world settings and the various factors responsible. Such studies are important from a public health services perspective in various settings around the world because they may lead to corrective action being taken at the institutional level.},
	doi = {10.1200/JGO.2016.007906},
	pmid = {30241224 [Indexed for MEDLINE]},
	note = {PMC6223484}
}

@ARTICLE{10.1111/bcpt.13093,
	author = {Geist MJP and Egerer G and Mikus G and Blank A and Hohmann N and Heinz WJ and Carls A},
	title = {Impact of patient education on plasma concentrations and effectiveness of posaconazole oral suspension under clinical conditions.},
	journal = {Basic Clin Pharmacol Toxicol},
	year = {2019},
	abstract = {Posaconazole prophylaxis is recommended for patients with acute myeloid leukaemia during induction chemotherapy. Although a tablet formulation with better oral bioavailability is available, some patients have to rely on the oral suspension in clinical routine. Therefore, effectiveness of posaconazole oral suspension under real-life clinical conditions and impact of patient education about the correct intake on its plasma concentrations were assessed in this study. Altogether 96 patients receiving 160 cycles of induction chemotherapy were retrospectively (40 patients) and prospectively (56 patients) analysed. Patients were assigned into two groups for each chemotherapy cycle according to the application of antifungal prophylaxis (A: posaconazole oral suspension, 200 mg three times a day ≥7 days; B: intake <7 days, fluconazole or no prophylaxis). Antifungal prophylaxis and therapy were analysed for each cycle. Additionally, plasma concentrations were determined from prospectively included subjects of group A who were intensively educated to perform a correct drug intake. Systemic antifungal therapy was statistically started less often in group A (26% vs 53%; P = 0.002). Posaconazole prophylaxis was associated with a lower risk of proven invasive fungal infection (P = 0.003). Median plasma concentration apparently increased between the first and second time of determination effected by an initial intensive on-site patient education. The clinical effectiveness of posaconazole oral suspension was confirmed. A detailed patient education at the beginning of the treatment with posaconazole oral suspensions seems to be of primary importance for efficient plasma concentrations.},
	doi = {10.1111/bcpt.13093},
	pmid = {29989301 [Indexed for MEDLINE]}
}

@ARTICLE{10.1200/JOP.17.00039,
	author = {Muluneh B and Schneider M and Faso A and Amerine L and Daniels R and Crisp B and Valgus J and Savage S},
	title = {Improved Adherence Rates and Clinical Outcomes of an Integrated, Closed-Loop, Pharmacist-Led Oral Chemotherapy Management Program.},
	journal = {J Oncol Pract},
	year = {2018},
	abstract = {PURPOSE: To address the growing use of oral anticancer therapy, an integrated, closed-loop, pharmacist-led oral chemotherapy management program was created within an academic medical center. METHODS: An integrated, closed-loop, pharmacy-led oral chemotherapy management program was established. From September 2014 until June 2015, demographic information, rates of adherence, patient understanding of treatment, pharmacist interventions, patient and provider satisfaction, and molecular response rates in patients with chronic myeloid leukemia (CML) were collected. RESULTS: After full implementation, 107 patients were enrolled in our oral chemotherapy management program from September 2014 until June 2015. All patients were educated before starting oral chemotherapy, and using pre- and postassessment tests, comprehension of oral chemotherapy treatment increased from 43% to 95%. Patient-reported adherence was 86% and 94.7% for the GI/breast and malignant hematology patient populations, respectively, and these were validated with medication possession ratio, revealing adherence rates of 85% and 93.9% for the GI/breast and malignant hematology patient populations, respectively. A total of 350 encounters with a clinical pharmacist and 318 adverse effects were reported, which led to 235 interventions. This program led to a higher major molecular response rate (83%) in our CML population compared with published clinical trials (average major molecular response rates, 40% and 60% with 1- and 2-year follow-up, respectively). CONCLUSION: An innovative model was developed and resulted in improved patient knowledge regarding oral chemotherapy, improved adherence rates that exceeded nationally established thresholds, and superior major molecular response outcomes for patients with CML compared with published literature. As a result, this model has produced the gold standard in managing patients receiving oral chemotherapy.},
	doi = {10.1200/JOP.17.00039},
	pmid = {29799768 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/pon.4774,
	author = {Martínez Ú and Brandon TH and Sutton SK and Simmons VN},
	title = {Associations between the smoking-relatedness of a cancer type, cessation attitudes and beliefs, and future abstinence among recent quitters.},
	abstract = {OBJECTIVE: Smoking after a diagnosis of cancer can negatively impact treatment outcomes and quality of life. It is important that patients quit smoking and remain abstinent regardless of cancer type. Some cancer types (eg, lung) have stronger links to smoking as a cause than do others (eg, colorectal). The aims of this study were to (1) assess associations between smoking-relatedness of the cancer type with beliefs and attitudes concerning smoking abstinence (eg, confidence, self-efficacy), and (2) assess these variables as predictors of future abstinence. METHODS: In this secondary analysis, cancer patients (N = 357) who quit smoking within the previous 90 days were assigned a code of 3, 2, or 1 according to the cancer type's level of smoking-relatedness: Very related (n = 134, thoracic and head and neck), Somewhat related (n = 93, acute myeloid leukemia, bladder, cervix, colorectal, esophageal, kidney, liver, pancreas, and stomach), and Unlikely related (n = 137, all other cancer types). RESULTS: Smoking-relatedness was positively associated with plan to stay smoke-free, maximum confidence in being smoke-free in 6 months, higher abstinence self-efficacy, and lower expected difficulty in staying smoke-free. Each of the 4 beliefs and attitude variables predicted abstinence 2 months later. Smoking-relatedness also predicted abstinence in a univariate model, but not in a multivariable model with the belief and attitude variables. Using backwards stepwise procedures, the final model included plan to stay smoke-free, confidence in being smoke-free, and abstinence self-efficacy. CONCLUSION: These results are consistent with our conceptualization of cessation motivation differing by smoking-relatedness of the cancer type and predicting future abstinence.},
	doi = {10.1002/pon.4774},
	pmid = {29785718 [Indexed for MEDLINE]},
	note = {PMC6156937}
}

@ARTICLE{10.1016/j.clml.2018.04.005,
	author = {Saglio G and Sharf G and Almeida A and Bogdanovic A and Bombaci F, Čugurović J and Deekes N, Garcia-Gutiérrez V, de Jong J and Narbutas Š and Westerweel P and Zackova D},
	title = {Considerations for Treatment-free Remission in Patients With Chronic Myeloid Leukemia: A Joint Patient-Physician Perspective.},
	journal = {Clin Lymphoma Myeloma Leuk},
	year = {2018},
	abstract = {Treatment-free remission (TFR) after discontinuation of tyrosine kinase inhibitor therapy is now an emerging treatment goal for patients with chronic myeloid leukemia, who have achieved a deep and stable response to treatment. Although guidance is now available, patients' questions regarding this progressive concept have yet to be addressed. The overall aim of this European Steering Group is a patient-centered approach that educates patients on their treatment options, including TFR, facilitates better patient-physician relationships, and meets patients' emotional and psychological needs. The present report outlines 5 key topic areas on discontinuing tyrosine kinase therapy and the implications of TFR for patient-physician consideration: what TFR is; when TFR is appropriate; which patients might and might not be eligible for TFR; and patients' considerations for discontinuing therapy, such as tyrosine kinase withdrawal syndrome, potential psychological implications, molecular recurrence, and repeat treatment. This Steering Group advocates that patients with chronic myeloid leukemia should have access to high-quality, frequent molecular monitoring and be treated in a specialist center with appropriate medical and psychological support. As patient concerns with attempting TFR become forefront in patient-physician discussions, a greater number of eligible patients might be willing to discontinue therapy.},
	doi = {10.1016/j.clml.2018.04.005},
	pmid = {29753691 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/cncr.31411,
	author = {Rea D and Ame S and Berger M and Cayuela JM and Charbonnier A and Coiteux V and Cony-Makhoul P and Dubruille V and Dulucq S and Etienne G and Legros L and Nicolini F and Roche-Lestienne C and Escoffre-Barbe M and Gardembas M and Guerci-Bresler A and Johnson-Ansah H and Rigal-Huguet F and Rousselot P and Mahon FX; French Chronic Myeloid Leukemia Study Group},
	title = {Discontinuation of tyrosine kinase inhibitors in chronic myeloid leukemia: Recommendations for clinical practice from the French Chronic Myeloid Leukemia Study Group.},
	journal = {Cancer},
	year = {2018},
	abstract = {BACKGROUND: The ultimate goal of chronic myeloid leukemia management in the tyrosine kinase inhibitor (TKI) era for patients who obtain deep molecular responses is maintaining a durable off-treatment response after treatment discontinuation; this situation is called treatment-free remission (TFR). Knowledge accumulated during the last 10 years justifies moving TFR strategies from research to clinical practice. METHODS: Twenty experts from the French Chronic Myeloid Leukemia Study Group (France Intergroupe des Leucémies Myéloïdes Chroniques), including 17 hematologists, 2 molecular biologists, and 1 cytogeneticist, critically reviewed published data with the goal of developing evidence-based recommendations for TKI discontinuation in clinical practice. RESULTS: Clinically relevant questions were addressed, including the selection of candidate patients (with known prognostic factors for outcomes taken into account), detailed monitoring procedures during the treatment-free phase, a definition of relapse requiring therapy resumption, and monitoring after treatment reintroduction. CONCLUSIONS: This work presents consensus statements with the aim of guiding physicians and biologists by means of pragmatic recommendations for safe TKI discontinuation in daily practice. Cancer 2018;124:2956-63. © 2018 American Cancer Society.},
	doi = {10.1002/cncr.31411},
	pmid = {29723417 [Indexed for MEDLINE]}
}

@ARTICLE{10.1093/tbm/ibx034,
	author = {Rocque GB and Williams CP and Halilova KI and Borate U and Jackson BE and Van Laar ES and Pisu M and Butler TW and Davis RS and Mehta A and Knight SJ and Safford MM},
	title = {Improving shared decision-making in chronic lymphocytic leukemia through multidisciplinary education.},
	journal = {Transl Behav Med},
	year = {2018},
	abstract = {New treatments for chronic lymphocytic leukemia (CLL) with excellent response rates and varying toxicity profiles have emerged in recent years, creating an opportunity for a patient's personal preferences to contribute to treatment decisions. We conducted a prospective, quasi-experimental pre- and post-evaluation of a multilevel educational program and its impact on knowledge of CLL and shared decision-making (SDM). We educated patients, lay navigators, nurses/advanced practice providers (APPs), and physicians. Patients were evaluated for change in patient activation, distress, desired role in decision-making, perception of decision-making, satisfaction with oncologist explanation of treatment choice, and knowledge of CLL. Lay navigators, nurses/APPs, and physicians were evaluated for change in CLL knowledge and perception of decision-making. Forty-four patients, 33 lay navigators, 27 nurses/APPs, and 27 physicians participated in the educational program. We observed trends toward improved patient activation, with 68% before education versus 76% after education reporting a Patient Activation Measure (PAM) score of 3 or 4. The percentage of patients desiring and perceiving SDM trended upward from 47% to 67% and from 35% to 49%, respectively. The percentage of patients understanding that CLL is incurable increased from 80% to 90%, as did reporting awareness of signs of progression (64% to 76%). Patients' satisfaction with their oncologists' explanations of therapy increased significantly from 83% to 95% (p = .03). CLL knowledge increased after education for lay navigators (36% vs 63%) and nurses/APPs (35% vs 69%), and remained high for physicians (85% vs 87%). Nurses/APPs and physicians perceived at least some patient involvement in decision-making at baseline, whereas 12% of patients and 23% of lay navigators perceived that physicians made decisions independently. This project demonstrated trends toward improvements in patient engagement, prognostic awareness, knowledge of signs of progression, and SDM. These promising findings should be tested in larger samples. There remains an opportunity for further improvement in SDM.},
	doi = {10.1093/tbm/ibx034},
	pmid = {29390159 [Indexed for MEDLINE]}
}
